patch:
diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 3f3f6c6e0d1a..72521b128cab 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -4607,6 +4607,16 @@ static Value *simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,
           match(Cond, m_c_LogicalOr(m_Specific(X), m_Specific(Y))))
         return X;
     }
+
+    // select (select X, Y, false), true, Y --> Y
+    if (match(Cond, m_Select(m_Value(), m_Value(Y), m_ZeroInt())) &&
+        match(TrueVal, m_One()) && Y == FalseVal)
+      return Y;
+
+    // select (select X, true, Y), Y, false --> Y
+    if (match(Cond, m_Select(m_Value(), m_One(), m_Value(Y))) &&
+        match(FalseVal, m_ZeroInt()) && Y == TrueVal)
+      return Y;
   }

   // select ?, X, X -> X

